('lg-rearsets-cbr10-rr-r-1', '', 'ชุดพักเท้าหน้าแต่งแบบเกียร์โยงทรงสนามแข่ง ใส่ Honda CBR1000RR-R', 'ชุดพักเท้าหน้าแต่งแบบเกียร์โยงทรงสนามแข่ง ใส่ Honda CBR1000RR-R', 6500, 'chassis', '["cbr600"]'::jsonb, '[]'::jsonb, true, 10, 'Alloy 6061+7075 ทั้ง', 'ชุดพักเท้าหน้าแต่งแบบเกียร์โยงทรงสนามแข่ง ใส่ Honda CBR1000RR-R ผลิตจาก Alloy 6061+7075 ทั้งชุดและกัด CNC Billet ทั้งชุดคงทนแข็งแรง ทดสอบในสนามแข่งมาแล้วหลายสนาม ชุดละ', 'ชุดพักเท้าหน้าแต่งแบบเกียร์โยงทรงสนามแข่ง ใส่ Honda CBR1000RR-R ผลิตจาก Alloy 6061+7075 ทั้งชุดและกัด CNC Billet ทั้งชุดคงทนแข็งแรง ทดสอบในสนามแข่งมาแล้วหลายสนาม ชุดละ', '["/legacy/webgigabike.com/cbr1000rrr/Rearsets-cbr10-RR-R-1.jpg","/legacy/webgigabike.com/cbr1000rrr/Rearsets-cbr10-RR-R-2.jpg"]'::jsonb, false, false, '["no_code"]'::jsonb),
('lg-cbr150-2020', '', 'อุปกรณ์ตกแต่ง CBR150r 2020 ใหม่ๆอยากแนะนำ น็อตแผงคอบน Honda CBR250rr M', 'อุปกรณ์ตกแต่ง CBR150r 2020 ใหม่ๆอยากแนะนำ น็อตแผงคอบน Honda CBR250rr M', 500, 'hardware', '["cbr250"]'::jsonb, '[]'::jsonb, true, 10, '', 'อุปกรณ์ตกแต่ง CBR150r 2020 ใหม่ๆอยากแนะนำ น็อตแผงคอบน Honda CBR250rr M24x1.0 ผลิตจาก Alloy CNC Billet Hard Anodize สวยงามแข็งแรง น้ำหนักเพียง 17 g. (มีสี ฮาร์ด) อันล่ะ', 'อุปกรณ์ตกแต่ง CBR150r 2020 ใหม่ๆอยากแนะนำ น็อตแผงคอบน Honda CBR250rr M24x1.0 ผลิตจาก Alloy CNC Billet Hard Anodize สวยงามแข็งแรง น้ำหนักเพียง 17 g. (มีสี ฮาร์ด) อันล่ะ', '["/legacy/webgigabike.com/CBR150/cbr150-2020.jpg","/legacy/webgigabike.com/CBR250/Nut-top.jpg"]'::jsonb, false, false, '["no_code"]'::jsonb),
('lg-cbr150-2024', '', 'อุปกรณ์ตกแต่ง CBR150r 2024 ใหม่ๆอยากแนะนำ ชุดแผงคอบนล่างแต่ง Honda CBR', 'อุปกรณ์ตกแต่ง CBR150r 2024 ใหม่ๆอยากแนะนำ ชุดแผงคอบนล่างแต่ง Honda CBR', 8000, 'suspension', '["cbr250"]'::jsonb, '[]'::jsonb, true, 10, '', 'อุปกรณ์ตกแต่ง CBR150r 2024 ใหม่ๆอยากแนะนำ ชุดแผงคอบนล่างแต่ง Honda CBR150rr รุ่นโช๊คหัวกลับขนาด 45mm. ออฟเซ็ดโช๊ค35องศา ผลิตจาก Alloy CNC Billet Hard Anodize สวยงามแข็งแรงทดสอบในสนามแข่งมาแล้ว น้ำหนักเพียง 1.57 kg. (มีสี ดำและฮาร์ด) ชุดล่ะ', 'อุปกรณ์ตกแต่ง CBR150r 2024 ใหม่ๆอยากแนะนำ ชุดแผงคอบนล่างแต่ง Honda CBR150rr รุ่นโช๊คหัวกลับขนาด 45mm. ออฟเซ็ดโช๊ค35องศา ผลิตจาก Alloy CNC Billet Hard Anodize สวยงามแข็งแรงทดสอบในสนามแข่งมาแล้ว น้ำหนักเพียง 1.57 kg. (มีสี ดำและฮาร์ด) ชุดล่ะ', '["/legacy/webgigabike.com/CBR150/cbr150-2024.jpg","/legacy/webgigabike.com/CBR150/Yoke-Set-cbr150-bk-35.jpg","/legacy/webgigabike.com/CBR150/Yoke-Set-cbr150-Hard-35.jpg"]'::jsonb, false, false, '["no_code"]'::jsonb),
('lg-footracing-1', '', 'อุปกรณ์ตกแต่ง CB150r ใหม่ๆอยากแนะนำ สเตอร์หลังอลูมิเนียม CB150R', 'อุปกรณ์ตกแต่ง CB150r ใหม่ๆอยากแนะนำ สเตอร์หลังอลูมิเนียม CB150R', 1600, 'drivetrain', '["cbr250"]'::jsonb, '[]'::jsonb, true, 10, 'Alloy 7075 CNC Billet', 'อุปกรณ์ตกแต่ง CB150r ใหม่ๆอยากแนะนำ สเตอร์หลังอลูมิเนียม CB150R ผลิตจาก Alloy 7075 CNC Billet พร้อมชุบสี Hard Anodize ใส่โซ่ 415-42,44/45/46/47/48/49/51 ฟัน อันละ', 'อุปกรณ์ตกแต่ง CB150r ใหม่ๆอยากแนะนำ สเตอร์หลังอลูมิเนียม CB150R ผลิตจาก Alloy 7075 CNC Billet พร้อมชุบสี Hard Anodize ใส่โซ่ 415-42,44/45/46/47/48/49/51 ฟัน อันละ', '["/legacy/webgigabike.com/CBR150/Footracing-1.jpg","/legacy/webgigabike.com/CBR150/Footracing-4.jpg","/legacy/webgigabike.com/CB150r/cb150r.jpg","/legacy/webgigabike.com/CBR150/Srocket-cbr150r-ha.jpg"]'::jsonb, false, false, '["no_code"]'::jsonb),
('lg-srocket-cbr150r-ha', '', 'สเตอร์หลังอลูมิเนียม CBR150R', 'สเตอร์หลังอลูมิเนียม CBR150R', 1600, 'drivetrain', '["cbr250"]'::jsonb, '[]'::jsonb, true, 10, 'Alloy 7075 CNC Billet', 'สเตอร์หลังอลูมิเนียม CBR150R ผลิตจาก Alloy 7075 CNC Billet พร้อมชุบสี Hard Anodize ใส่โซ่ 415-42,44/45/46/47/48/49/51 ฟัน อันละ', 'สเตอร์หลังอลูมิเนียม CBR150R ผลิตจาก Alloy 7075 CNC Billet พร้อมชุบสี Hard Anodize ใส่โซ่ 415-42,44/45/46/47/48/49/51 ฟัน อันละ', '["/legacy/webgigabike.com/CBR150/Srocket-cbr150r-ha.jpg"]'::jsonb, false, false, '["no_code"]'::jsonb),
('lg-boot-weel', '', 'ชุดบู๊ทล้อหน้าและหลังแต่ง ใส่ Honda CBR250rr ใส่เข้ากับล้อเดิมแบบไม่ต้', 'ชุดบู๊ทล้อหน้าและหลังแต่ง ใส่ Honda CBR250rr ใส่เข้ากับล้อเดิมแบบไม่ต้', 1600, 'accessories', '["cbr250"]'::jsonb, '[]'::jsonb, true, 10, '', 'ชุดบู๊ทล้อหน้าและหลังแต่ง ใส่ Honda CBR250rr ใส่เข้ากับล้อเดิมแบบไม่ต้องถอดซิลกันฝุ่นออก ล้อหมุนลื่นขึ้นมากใส่ล้อเข้ากับตัวรถง่ายมากๆ และบู๊ทไม่สามารถล่นออกมาได้เลย ผลิตจาก Alloy 7075 CNC Billet ชุบสี อโนไดซ์ แบบ Hard Anodize เพิ่มความแข็งมากขึ้นแต่เบาอย่างกับนุ่น สามารถกันรอยได้ดี และช่วยระบายความร้อนของลูกปืนล้อได้เร็วยิ่งขึ้น (สีเทา-ฮาร์ท) ชุดละ', 'ชุดบู๊ทล้อหน้าและหลังแต่ง ใส่ Honda CBR250rr ใส่เข้ากับล้อเดิมแบบไม่ต้องถอดซิลกันฝุ่นออก ล้อหมุนลื่นขึ้นมากใส่ล้อเข้ากับตัวรถง่ายมากๆ และบู๊ทไม่สามารถล่นออกมาได้เลย ผลิตจาก Alloy 7075 CNC Billet ชุบสี อโนไดซ์ แบบ Hard Anodize เพิ่มความแข็งมากขึ้นแต่เบาอย่างกับนุ่น สามารถกันรอยได้ดี และช่วยระบายความร้อนของลูกปืนล้อได้เร็วยิ่งขึ้น (สีเทา-ฮาร์ท) ชุดละ', '["/legacy/webgigabike.com/CBR250/Boot-Weel.jpg"]'::jsonb, false, false, '["no_code","no_category"]'::jsonb),
